+import { mkdir, readFile, writeFile } from 'node:fs/promises'
+import { dirname, resolve } from 'pathe'
+import { slash } from '@vitest/utils/helpers'
+import { smoothDurations, type DurationObservation, type DurationSmoothing } from './duration-smoothing'
+
+export type DurationHistory = Record<string, DurationObservation[]>
+
+function observations(value: unknown): DurationObservation[] | undefined {
+  if (typeof value === 'number' && Number.isFinite(value)) return [{ duration: value, recordedAt: 0 }]
+  const entries = typeof value === 'object' && value !== null && 'observations' in value
+    ? (value as { observations: unknown }).observations
+    : [value]
+  if (!Array.isArray(entries) || entries.some(entry => !entry || typeof entry !== 'object' || !Number.isFinite((entry as DurationObservation).duration) || !Number.isFinite((entry as DurationObservation).recordedAt))) return undefined
+  return entries as DurationObservation[]
+}
+
+export async function readDurationHistory(root: string, path: string, ttl: number): Promise<DurationHistory | null> {
+  try {
+    const data: unknown = JSON.parse(await readFile(resolve(root, path), 'utf8'))
+    if (!data || typeof data !== 'object' || Array.isArray(data)) return null
+    const cutoff = Date.now() - ttl
+    const result: DurationHistory = {}
+    for (const [file, value] of Object.entries(data)) {
+      const entries = observations(value)
+      if (!entries) return null
+      result[slash(file)] = ttl > 0 ? entries.filter(entry => entry.recordedAt === 0 || entry.recordedAt >= cutoff) : entries
+    }
+    return result
+  }
+  catch {
+    return null
+  }
+}
+
+export function durationFromHistory(history: DurationHistory, file: string, smoothing: DurationSmoothing): number | undefined {
+  const entries = history[slash(file)]
+  return entries?.length ? smoothDurations(entries, smoothing) : undefined
+}
+
+export async function writeDurationHistory(root: string, path: string, maxRuns: number, durations: Record<string, number>): Promise<void> {
+  const file = resolve(root, path)
+  const existing = await readDurationHistory(root, path, 0) || {}
+  const recordedAt = Date.now()
+  for (const [name, duration] of Object.entries(durations)) {
+    const entries = [...(existing[slash(name)] || []), { duration: Math.round(duration), recordedAt }]
+      .sort((a, b) => b.recordedAt - a.recordedAt)
+      .slice(0, maxRuns)
+    existing[slash(name)] = entries
+  }
+  const serialized = Object.fromEntries(Object.entries(existing).map(([name, entries]) => [name, maxRuns === 1 ? entries[0] : { observations: entries }]))
+  await mkdir(dirname(file), { recursive: true })
+  await writeFile(file, `${JSON.stringify(serialized, null, 2)}\
`)
+}
