+  return entries as DurationObservation[]
+}
+
+export async function readDurationHistory(root: string, path: string, ttl: number): Promise<DurationHistory | null> {
+  try {
+    const data: unknown = JSON.parse(await readFile(resolve(root, path), 'utf8'))
+    if (!data || typeof data !== 'object' || Array.isArray(data)) return null
+    const cutoff = Date.now() - ttl
+    const result: DurationHistory = {}
+    for (const [file, value] of Object.entries(data)) {
+      const entries = observations(value)
+      if (!entries) return null
+      result[slash(file)] = ttl > 0 ? entries.filter(entry => entry.recordedAt === 0 || entry.recordedAt >= cutoff) : entries
+    }
+    return result
+  }
+  catch {
+    return null
+  }
